"""Wire Flow D into live DataQ: iceberg connection + suite + checks + schedule + Olivia share.

Secrets arrive via env (PG_DSN, ADLS_KEY, DATAQ_PAT) — never printed. Prints ids/statuses only.
"""

import json
import os
import urllib.request

BASE = "https://dataq-app-frontend.purplefield-f7322a1b.westus2.azurecontainerapps.io/api/v1"
HDRS = {
    "Authorization": "Bearer " + os.environ["DATAQ_PAT"],
    "Content-Type": "application/json",
}


def call(method: str, path: str, body: dict | None = None) -> dict:
    req = urllib.request.Request(
        BASE + path,
        data=json.dumps(body).encode() if body is not None else None,
        headers=HDRS,
        method=method,
    )
    try:
        with urllib.request.urlopen(req, timeout=90) as r:
            return json.load(r) if r.length != 0 else {}
    except urllib.error.HTTPError as e:
        detail = e.read().decode()[:400]
        raise SystemExit(f"{method} {path} -> {e.code}: {detail}") from e


account = os.environ["ADLS_ACCOUNT"]

# 1. Connection (idempotent-ish: reuse if a harness-iceberg connection exists)
existing = [
    c
    for c in call("GET", "/connections")
    if isinstance(c, dict) and c.get("name") == "harness-iceberg"
]
if existing:
    conn = existing[0]
    print("connection exists:", conn["id"])
else:
    conn = call(
        "POST",
        "/connections",
        {
            "name": "harness-iceberg",
            "type": "iceberg",
            "env": "dev",
            "config": {
                "catalog_name": "harness",
                "catalog_type": "sql",
                "catalog_uri": os.environ["PG_DSN"],
                "warehouse": f"abfss://iceberg@{account}.dfs.core.windows.net/warehouse",
                "properties": {
                    "py-io-impl": "pyiceberg.io.fsspec.FsspecFileIO",
                    "adls.account-name": account,
                },
                "secret_property": "adls.account-key",
            },
            "secret": os.environ["ADLS_KEY"],
        },
    )
    print("connection created:", conn["id"])

call("POST", f"/connections/{conn['id']}/test")
print("connection test: OK")

# 2. Suite
suites = call("GET", "/suites")
items = suites if isinstance(suites, list) else suites.get("items", [])
match = [s for s in items if s.get("name") == "flow_d_iceberg"]
if match:
    suite = match[0]
    print("suite exists:", suite["id"])
else:
    suite = call(
        "POST",
        "/suites",
        {
            "name": "flow_d_iceberg",
            "description": "Flow D — native Iceberg PO table (retail.purchase_orders); schedule-driven, no orchestrator (ADR 0030).",
            "connection_id": conn["id"],
            "target": {"table": "purchase_orders", "namespace": "retail"},
        },
    )
    print("suite created:", suite["id"])
sid = suite["id"]

# 3. Checks (3 expectations biting on seeded issues + 2 native monitors)
checks = [
    {
        "name": "po_id not null",
        "expectation_type": "expect_column_values_to_not_be_null",
        "config": {"column": "po_id"},
    },
    {
        "name": "supplier_id not null (seeded nulls)",
        "expectation_type": "expect_column_values_to_not_be_null",
        "config": {"column": "supplier_id"},
    },
    {
        "name": "order_qty >= 0 (seeded negatives)",
        "expectation_type": "expect_column_values_to_be_between",
        "config": {"column": "order_qty", "min_value": 0},
    },
    {
        "name": "PO freshness (load_ts)",
        "kind": "freshness",
        "expectation_type": "monitor:freshness",
        "config": {"column": "load_ts"},
        "fail_threshold": 48,
    },
    {
        "name": "PO tick volume band",
        "kind": "volume",
        "expectation_type": "monitor:volume",
        "config": {"min_rows": 100},
    },
]
have = {c.get("name") for c in call("GET", f"/suites/{sid}/checks")}
for c in checks:
    if c["name"] in have:
        print("check exists:", c["name"])
        continue
    call("POST", f"/suites/{sid}/checks", c)
    print("check created:", c["name"])

# 4. Schedule (04:00 UTC, after the 03:00 writer cron)
scheds = call("GET", "/schedules")
sitems = scheds if isinstance(scheds, list) else scheds.get("items", [])
if any(s.get("suite_id") == sid for s in sitems):
    print("schedule exists")
else:
    call("POST", "/schedules", {"suite_id": sid, "cron": "0 4 * * *", "timezone": "UTC"})
    print("schedule created: 0 4 * * * UTC")

# 5. Share with Olivia (edit)
users = call("GET", "/admin/users")
uitems = users if isinstance(users, list) else users.get("items", [])
olivia = [u for u in uitems if "olivia" in (u.get("email") or "").lower()]
if not olivia:
    raise SystemExit("no Olivia user found: " + ", ".join(u.get("email", "?") for u in uitems))
oid = olivia[0]["id"]
shares = call("GET", f"/suites/{sid}/shares")
shitems = shares if isinstance(shares, list) else shares.get("items", [])
if any(sh.get("user_id") == oid for sh in shitems):
    print("share exists for", olivia[0]["email"])
else:
    call("POST", f"/suites/{sid}/shares", {"user_id": oid, "permission": "edit"})
    print("shared (edit) with", olivia[0]["email"])

print("SUITE_ID=" + sid)

